class Solution {
public:
    int clumsy(int n) {
        if (n <= 2) return n;
        long long ans = n;
        n--;
        int count = 0;
        while (n > 0) {
            if (count % 4 == 0) ans *= n;
            else if (count % 4 == 1) ans /= n;
            else if (count % 4 == 2) ans += n;
            else ans -= n;
            n--;
            count++;
        }
        return (int)ans;
    }
};
```
